import React, { StrictMode, Component, ReactNode } from 'react';
import { createRoot } from 'react-dom/client';
import { App } from './App';
import './index.css';

/**
 * Enterprise Error Boundary
 * Catch-all for rendering failures to prevent the 'White Page' syndrome.
 */
class GlobalErrorBoundary extends Component<{children: ReactNode}, {hasError: boolean, error: Error | null}> {
  constructor(props: {children: ReactNode}) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error) {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: any) {
    console.error("Critical Nexus Core Boot Failure:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ 
          height: '100vh', display: 'flex', flexDirection: 'column', 
          alignItems: 'center', justifyContent: 'center', fontFamily: 'sans-serif',
          background: '#f8fafc', color: '#1e293b', padding: '20px', textAlign: 'center' 
        }}>
          <h1 style={{ fontSize: '24px', fontWeight: 'bold' }}>Nexus Core System Halt</h1>
          <p style={{ marginTop: '10px', color: '#64748b' }}>A critical dependency or runtime error occurred.</p>
          <pre style={{ 
            marginTop: '20px', padding: '15px', background: '#fee2e2', color: '#991b1b', 
            borderRadius: '8px', fontSize: '12px', maxWidth: '600px', overflow: 'auto'
          }}>
            {this.state.error?.toString()}
          </pre>
          <button 
            onClick={() => window.location.reload()}
            style={{ 
              marginTop: '30px', padding: '10px 20px', background: '#2563eb', 
              color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer'
            }}
          >
            Restart Application
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}

const rootElement = document.getElementById('root');

if (!rootElement) {
  throw new Error('FATAL: Could not find root element "#root" to mount Nexus Core.');
}

try {
  const root = createRoot(rootElement);
  root.render(
    <StrictMode>
      <GlobalErrorBoundary>
        <App />
      </GlobalErrorBoundary>
    </StrictMode>
  );
} catch (e) {
  console.error("DOM Mounting Exception:", e);
}

